import React, { useState, useEffect } from "react";
import {
  Box,
  Container,
  Typography,
  Card,
  CardContent,
  Button,
  Chip,
  LinearProgress,
  Checkbox,
  Accordion,
  AccordionSummary,
  AccordionDetails,
  CircularProgress,
  Alert,
  Grid,
  Link,
} from "@mui/material";
import {
  ExpandMore,
  CheckCircle,
  RadioButtonUnchecked,
  School,
  ArrowBack,
  OpenInNew,
  Star,
  Print,
} from "@mui/icons-material";
import { useNavigate, useParams } from "react-router-dom";
import api from "../services/api";
import { useAuth } from "../context/AuthContext";

const DIFFICULTY_COLORS = {
  Beginner: "#10B981",
  Intermediate: "#3B82F6",
  Advanced: "#F59E0B",
  Expert: "#EF4444",
};
const RESOURCE_ICONS = {
  Course: "📚",
  Tutorial: "📖",
  Documentation: "📄",
  Practice: "💻",
  Video: "🎥",
  Book: "📕",
};
const PLATFORM_COLORS = {
  freeCodeCamp: "#F03000",
  Coursera: "#0056D2",
  YouTube: "#FF0000",
  Kaggle: "#20BEFF",
  HackerRank: "#00EA64",
  W3Schools: "#04AA6D",
  default: "#6C63FF",
};

export default function RoadmapPage() {
  const { slug } = useParams();
  const navigate = useNavigate();
  const { user, isAuthenticated } = useAuth();
  const [roadmap, setRoadmap] = useState(null);
  const [completedSteps, setCompletedSteps] = useState([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");
  const [expanded, setExpanded] = useState(0);

  useEffect(() => {
    const fetch = async () => {
      try {
        const res = await api.get(`/roadmap/${slug}`);
        setRoadmap(res.data.roadmap);
        if (res.data.userProgress) {
          setCompletedSteps(res.data.userProgress.completedSteps || []);
        }
      } catch (e) {
        setError("Roadmap not found for this career field.");
      } finally {
        setLoading(false);
      }
    };
    fetch();
  }, [slug]);

  const toggleStep = async (stepNumber) => {
    const newCompleted = completedSteps.includes(stepNumber)
      ? completedSteps.filter((s) => s !== stepNumber)
      : [...completedSteps, stepNumber];
    setCompletedSteps(newCompleted);

    if (isAuthenticated) {
      setSaving(true);
      try {
        await api.put(`/roadmap/${slug}/progress`, {
          completedSteps: newCompleted,
        });
      } catch (e) {
        console.error("Failed to save progress");
      } finally {
        setSaving(false);
      }
    }
  };

  if (loading)
    return (
      <Box
        sx={{
          minHeight: "100vh",
          bgcolor: "#0A0E1A",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
        }}
      >
        <CircularProgress />
      </Box>
    );
  if (error || !roadmap)
    return (
      <Box
        sx={{
          minHeight: "100vh",
          bgcolor: "#0A0E1A",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
        }}
      >
        <Alert severity="warning">
          {error || "Roadmap not available yet for this career."}
        </Alert>
      </Box>
    );

  const progress =
    roadmap.steps?.length > 0
      ? Math.round((completedSteps.length / roadmap.steps.length) * 100)
      : 0;

  return (
    <Box sx={{ minHeight: "100vh", bgcolor: "#0A0E1A", py: 5 }}>
      <Container maxWidth="lg">
        <Box
          sx={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            mb: 3,
          }}
        >
          <Button
            startIcon={<ArrowBack />}
            onClick={() => navigate(-1)}
            sx={{ color: "text.secondary" }}
          >
            Back
          </Button>
          <Button
            variant="outlined"
            startIcon={<Print />}
            onClick={() => window.print()}
            sx={{
              borderColor: "rgba(255,255,255,0.2)",
              color: "text.secondary",
              "&:hover": { borderColor: "primary.main", color: "primary.main" },
            }}
          >
            Print / Save PDF
          </Button>
        </Box>
        {/* Header */}
        <Card
          sx={{
            background:
              "linear-gradient(135deg, rgba(108,99,255,0.1), rgba(0,212,170,0.05))",
            border: "1px solid rgba(108,99,255,0.2)",
            mb: 4,
          }}
        >
          <CardContent sx={{ p: { xs: 3, md: 4 } }}>
            <Grid container spacing={3} alignItems="center">
              <Grid item xs={12} md={8}>
                <Chip
                  icon={<School sx={{ fontSize: "14px !important" }} />}
                  label="Learning Roadmap"
                  sx={{
                    mb: 2,
                    bgcolor: "rgba(108,99,255,0.15)",
                    color: "#9C94FF",
                  }}
                />
                <Typography variant="h3" sx={{ fontWeight: 800, mb: 1 }}>
                  {roadmap.careerField}
                </Typography>
                <Typography color="text.secondary">
                  ⏱️ Estimated duration: {roadmap.totalDuration} &nbsp;•&nbsp;{" "}
                  {roadmap.steps?.length} learning steps
                </Typography>
              </Grid>
              <Grid item xs={12} md={4}>
                <Box sx={{ textAlign: { md: "right" } }}>
                  <Typography
                    variant="h2"
                    sx={{
                      fontWeight: 900,
                      background: "linear-gradient(135deg, #6C63FF, #00D4AA)",
                      backgroundClip: "text",
                      WebkitBackgroundClip: "text",
                      WebkitTextFillColor: "transparent",
                    }}
                  >
                    {progress}%
                  </Typography>
                  <Typography
                    color="text.secondary"
                    variant="body2"
                    sx={{ mb: 1.5 }}
                  >
                    {completedSteps.length}/{roadmap.steps?.length} steps
                    completed
                  </Typography>
                  <LinearProgress
                    variant="determinate"
                    value={progress}
                    sx={{
                      height: 10,
                      borderRadius: 10,
                      bgcolor: "rgba(255,255,255,0.06)",
                      "& .MuiLinearProgress-bar": {
                        background: "linear-gradient(90deg, #6C63FF, #00D4AA)",
                        borderRadius: 10,
                      },
                    }}
                  />
                  {!isAuthenticated && (
                    <Typography
                      variant="caption"
                      color="text.secondary"
                      sx={{ mt: 1, display: "block" }}
                    >
                      <Link
                        component="button"
                        onClick={() => navigate("/register")}
                        sx={{ color: "primary.light", cursor: "pointer" }}
                      >
                        Create account
                      </Link>{" "}
                      to save progress
                    </Typography>
                  )}
                  {saving && (
                    <Typography variant="caption" color="text.secondary">
                      Saving...
                    </Typography>
                  )}
                </Box>
              </Grid>
            </Grid>
          </CardContent>
        </Card>

        {/* Steps */}
        <Box sx={{ position: "relative" }}>
          {/* Timeline line */}
          <Box
            sx={{
              position: "absolute",
              left: { xs: 20, md: 28 },
              top: 0,
              bottom: 0,
              width: 2,
              bgcolor: "rgba(255,255,255,0.06)",
              zIndex: 0,
            }}
          />

          {roadmap.steps?.map((step, idx) => {
            const isCompleted = completedSteps.includes(step.stepNumber);
            return (
              <Box
                key={step.stepNumber}
                sx={{ position: "relative", pl: { xs: 7, md: 9 }, mb: 3 }}
              >
                {/* Timeline dot */}
                <Box
                  onClick={() => toggleStep(step.stepNumber)}
                  sx={{
                    position: "absolute",
                    left: { xs: 12, md: 20 },
                    top: 20,
                    width: 18,
                    height: 18,
                    borderRadius: "50%",
                    cursor: "pointer",
                    zIndex: 1,
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    transition: "all 0.2s",
                    bgcolor: isCompleted ? "#00D4AA" : "rgba(255,255,255,0.1)",
                    border: `2px solid ${isCompleted ? "#00D4AA" : "rgba(255,255,255,0.2)"}`,
                    "&:hover": {
                      transform: "scale(1.3)",
                      borderColor: "#00D4AA",
                    },
                  }}
                >
                  {isCompleted && (
                    <CheckCircle sx={{ fontSize: 12, color: "white" }} />
                  )}
                </Box>

                <Accordion
                  expanded={expanded === idx}
                  onChange={() => setExpanded(expanded === idx ? -1 : idx)}
                  sx={{
                    background: isCompleted
                      ? "rgba(0,212,170,0.05)"
                      : "rgba(17,24,39,0.95)",
                    border: `1px solid ${isCompleted ? "rgba(0,212,170,0.25)" : "rgba(255,255,255,0.06)"}`,
                    borderRadius: "12px !important",
                    "&:before": { display: "none" },
                    mb: 0,
                  }}
                >
                  <AccordionSummary
                    expandIcon={<ExpandMore />}
                    sx={{ px: 3, py: 1.5 }}
                  >
                    <Box
                      sx={{
                        display: "flex",
                        alignItems: "center",
                        gap: 2,
                        width: "100%",
                        mr: 2,
                      }}
                    >
                      <Checkbox
                        checked={isCompleted}
                        onChange={() => toggleStep(step.stepNumber)}
                        onClick={(e) => e.stopPropagation()}
                        sx={{
                          p: 0,
                          color: "rgba(255,255,255,0.2)",
                          "&.Mui-checked": { color: "#00D4AA" },
                        }}
                      />
                      <Box sx={{ flex: 1, minWidth: 0 }}>
                        <Box
                          sx={{
                            display: "flex",
                            alignItems: "center",
                            gap: 1.5,
                            flexWrap: "wrap",
                          }}
                        >
                          <Typography
                            variant="caption"
                            sx={{ color: "primary.main", fontWeight: 700 }}
                          >
                            STEP {step.stepNumber}
                          </Typography>
                          {step.milestone && (
                            <Chip
                              label="Milestone"
                              size="small"
                              icon={
                                <Star
                                  sx={{
                                    fontSize: "12px !important",
                                    color: "#F59E0B !important",
                                  }}
                                />
                              }
                              sx={{
                                bgcolor: "rgba(245,158,11,0.1)",
                                color: "#F59E0B",
                                border: "1px solid rgba(245,158,11,0.3)",
                                height: 20,
                                fontSize: 10,
                              }}
                            />
                          )}
                          <Chip
                            label={step.difficulty}
                            size="small"
                            sx={{
                              bgcolor: `${DIFFICULTY_COLORS[step.difficulty]}15`,
                              color: DIFFICULTY_COLORS[step.difficulty],
                              height: 20,
                              fontSize: 10,
                            }}
                          />
                          <Typography variant="caption" color="text.secondary">
                            ⏱️ {step.duration}
                          </Typography>
                        </Box>
                        <Typography
                          variant="h6"
                          sx={{
                            fontWeight: 700,
                            mt: 0.3,
                            textDecoration: isCompleted
                              ? "line-through"
                              : "none",
                            opacity: isCompleted ? 0.6 : 1,
                          }}
                        >
                          {step.title}
                        </Typography>
                      </Box>
                    </Box>
                  </AccordionSummary>

                  <AccordionDetails sx={{ px: 3, pb: 3 }}>
                    <Typography
                      color="text.secondary"
                      sx={{ mb: 3, lineHeight: 1.7 }}
                    >
                      {step.description}
                    </Typography>

                    {/* Skills */}
                    {step.skills?.length > 0 && (
                      <Box sx={{ mb: 3 }}>
                        <Typography
                          variant="caption"
                          sx={{
                            fontWeight: 700,
                            color: "text.secondary",
                            textTransform: "uppercase",
                            letterSpacing: 1,
                          }}
                        >
                          Skills you'll learn
                        </Typography>
                        <Box
                          sx={{
                            display: "flex",
                            flexWrap: "wrap",
                            gap: 1,
                            mt: 1,
                          }}
                        >
                          {step.skills.map((s) => (
                            <Chip
                              key={s}
                              label={s}
                              size="small"
                              sx={{
                                bgcolor: "rgba(108,99,255,0.12)",
                                color: "#9C94FF",
                                border: "1px solid rgba(108,99,255,0.25)",
                              }}
                            />
                          ))}
                        </Box>
                      </Box>
                    )}

                    {/* Resources */}
                    {step.resources?.length > 0 && (
                      <Box>
                        <Typography
                          variant="caption"
                          sx={{
                            fontWeight: 700,
                            color: "text.secondary",
                            textTransform: "uppercase",
                            letterSpacing: 1,
                          }}
                        >
                          Resources
                        </Typography>
                        <Grid container spacing={1.5} sx={{ mt: 0.5 }}>
                          {step.resources.map((r, ri) => (
                            <Grid item xs={12} sm={6} key={ri}>
                              <Box
                                component={Link}
                                href={r.url}
                                target="_blank"
                                rel="noopener noreferrer"
                                underline="none"
                                sx={{
                                  display: "flex",
                                  alignItems: "center",
                                  gap: 1.5,
                                  p: 1.5,
                                  borderRadius: 2,
                                  bgcolor: "rgba(255,255,255,0.03)",
                                  border: "1px solid rgba(255,255,255,0.06)",
                                  cursor: "pointer",
                                  transition: "all 0.2s",
                                  "&:hover": {
                                    bgcolor: "rgba(255,255,255,0.07)",
                                    borderColor:
                                      PLATFORM_COLORS[r.platform] ||
                                      PLATFORM_COLORS.default,
                                  },
                                }}
                              >
                                <Typography sx={{ fontSize: "1.1rem" }}>
                                  {RESOURCE_ICONS[r.type] || "📌"}
                                </Typography>
                                <Box sx={{ flex: 1, minWidth: 0 }}>
                                  <Typography
                                    variant="caption"
                                    sx={{
                                      fontWeight: 700,
                                      display: "block",
                                      color:
                                        PLATFORM_COLORS[r.platform] ||
                                        PLATFORM_COLORS.default,
                                      fontSize: 10,
                                      textTransform: "uppercase",
                                    }}
                                  >
                                    {r.platform}
                                  </Typography>
                                  <Typography
                                    variant="body2"
                                    sx={{
                                      fontWeight: 600,
                                      color: "text.primary",
                                      overflow: "hidden",
                                      textOverflow: "ellipsis",
                                      whiteSpace: "nowrap",
                                    }}
                                  >
                                    {r.title}
                                  </Typography>
                                </Box>
                                <Box
                                  sx={{
                                    display: "flex",
                                    flexDirection: "column",
                                    alignItems: "flex-end",
                                    gap: 0.3,
                                  }}
                                >
                                  <OpenInNew
                                    sx={{
                                      fontSize: 14,
                                      color: "text.secondary",
                                    }}
                                  />
                                  {r.isFree && (
                                    <Chip
                                      label="Free"
                                      size="small"
                                      sx={{
                                        height: 16,
                                        fontSize: 9,
                                        bgcolor: "rgba(16,185,129,0.15)",
                                        color: "#10B981",
                                      }}
                                    />
                                  )}
                                </Box>
                              </Box>
                            </Grid>
                          ))}
                        </Grid>
                      </Box>
                    )}
                  </AccordionDetails>
                </Accordion>
              </Box>
            );
          })}
        </Box>

        {/* Completion */}
        {progress === 100 && (
          <Card
            sx={{
              mt: 4,
              background:
                "linear-gradient(135deg, rgba(0,212,170,0.15), rgba(16,185,129,0.05))",
              border: "1px solid rgba(0,212,170,0.3)",
              textAlign: "center",
            }}
          >
            <CardContent sx={{ py: 4 }}>
              <Typography sx={{ fontSize: "3rem", mb: 1 }}>🎉</Typography>
              <Typography
                variant="h4"
                sx={{ fontWeight: 800, color: "#00D4AA", mb: 1 }}
              >
                Roadmap Complete!
              </Typography>
              <Typography color="text.secondary" sx={{ mb: 3 }}>
                You've completed all steps in the {roadmap.careerField} roadmap.
                Ready for your next challenge?
              </Typography>
              <Button
                variant="contained"
                onClick={() => navigate("/explore")}
                sx={{
                  background: "linear-gradient(135deg, #6C63FF, #00D4AA)",
                  mr: 2,
                }}
              >
                Explore More Careers
              </Button>
              <Button
                variant="outlined"
                onClick={() => navigate("/dashboard")}
                sx={{ borderColor: "rgba(255,255,255,0.15)" }}
              >
                Dashboard
              </Button>
            </CardContent>
          </Card>
        )}
      </Container>
    </Box>
  );
}
